import "@radix-ui/themes/styles.css";
import { Box, ThemePanel, Container, Flex, Section, Heading, Text} from "@radix-ui/themes";
import './App.css';
import { useState } from "react";

const About = () => {
    return (
        <Box>
        <Box mt="7" id = "about" height="5000px">
            <Text size="4" style={{color: "rgba(255, 255, 255, 0.73)"}}>
                I am a full stack web developer with a passion for creating custom, scalable software. I have a background in business and a love for technology. I have experience with a variety of programming languages and frameworks, and I am always looking to learn more. I am dedicated to helping companies thrive on the web.
            </Text>
            <Text size="4" style={{color: "rgba(255, 255, 255, 0.73)"}}>

            </Text>
        </Box>
        </Box>
    )
}

export default About;
